type Task_Group_Stats is record
   Spawned   : Interfaces.Unsigned_64 := 0;
   Completed : Interfaces.Unsigned_64 := 0;
   Failed    : Interfaces.Unsigned_64 := 0;
   Cancelled : Interfaces.Unsigned_64 := 0;
   Pending   : Natural := 0;
end record;

